INSERT OR IGNORE INTO produtos (slug,title,description,lp_slug,icon,includes,cta_title,cta_description,cta_whatsapp_msg,active,ordem) VALUES ('corporativo','Ensaio Corporativo','Fotos profissionais para impulsionar sua imagem corporativa. Perfeitas para LinkedIn, sites institucionais, materiais de marketing e comunicação empresarial.','corporativo','<svg xmlns=''http://www.w3.org/2000/svg'' viewBox=''0 0 24 24'' fill=''none'' stroke=''currentColor'' stroke-width=''2'' stroke-linecap=''round'' stroke-linejoin=''round''><rect x=''2'' y=''7'' width=''20'' height=''14'' rx=''2'' ry=''2''/><path d=''M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2''/><line x1=''12'' y1=''12'' x2=''12'' y2=''12''/><path d=''M2 12h20''/></svg>','["Fotos digitais em alta resolução","Fotos enviadas por email","Para garantia da vaga é necessário um sinal de R$100.","Os pacotes contemplam ensaios individuais, para equipe é cobrado R$70 adicionais por pessoa.","Limite de 3 pessoas por ensaio.","No pacote está incluso apenas a cobertura fotográfica , looks e make são por conta da cliente.","Oferecemos o serviço de make por R$120, sendo necessário confirmar junto ao agendamento.","* Para necessidades diferentes dos pacotes, por favor, entre em contato.","Orçamento válido por 30 dias a partir da data de recebimento.","Orientação de postura e expressão durante a sessão","Tratamento profissional das imagens"]','Pronto para impulsionar sua imagem profissional?','Entre em contato e agende seu ensaio corporativo.','Olá! Gostaria de agendar um ensaio corporativo (mensagem do site)',1,1);
INSERT OR IGNORE INTO produtos (slug,title,description,lp_slug,icon,includes,cta_title,cta_description,cta_whatsapp_msg,active,ordem) VALUES ('dia-das-maes','Ensaio Dia das Mães','Fotos profissionais para celebrar o Dia das Mães. Perfeitas para registrar momentos especiais e criar lembranças inesquecíveis.','dia-das-maes','<svg viewBox="0 0 16 16" xmlns="http://www.w3.org/2000/svg"><path fill-rule="evenodd" clip-rule="evenodd" d="M8 0C6.89543 0 6 0.895431 6 2V2.0359L5.96891 2.01795C5.01233 1.46566 3.78915 1.79341 3.23686 2.75C2.68458 3.70659 3.01233 4.92977 3.96891 5.48205L4 5.5L3.96891 5.51795C3.01233 6.07023 2.68458 7.29342 3.23686 8.25C3.78915 9.20658 5.01233 9.53434 5.96891 8.98205L6 8.9641V9C6 10.1046 6.89543 11 8 11C9.10457 11 10 10.1046 10 9V8.9641L10.0311 8.98205C10.9877 9.53434 12.2109 9.20658 12.7631 8.25C13.3154 7.29342 12.9877 6.07023 12.0311 5.51795L12 5.5L12.0311 5.48205C12.9877 4.92977 13.3154 3.70659 12.7631 2.75C12.2109 1.79341 10.9877 1.46566 10.0311 2.01795L10 2.0359V2C10 0.895431 9.10457 0 8 0ZM7.99995 7C8.82838 7 9.49995 6.32843 9.49995 5.5C9.49995 4.67157 8.82838 4 7.99995 4C7.17152 4 6.49995 4.67157 6.49995 5.5C6.49995 6.32843 7.17152 7 7.99995 7Z"></path> <path d="M7 16H6C3.23858 16 1 13.7614 1 11V10H2C4.76142 10 7 12.2386 7 15V16Z"></path> <path d="M10 16H9V15C9 12.2386 11.2386 10 14 10H15V11C15 13.7614 12.7614 16 10 16Z"></path></svg>','["<span class=\"highlight\">* A Necessaire é ofertada para os 15 primeiros, temos 11 unidades restantes.</span>","Fotos digitais em alta resolução","Fotos enviadas por email","Para garantia da vaga é necessário um sinal de R$100.","Limite de 4 pessoas por ensaio.","No pacote está incluso apenas a cobertura fotográfica , looks e make são por conta da cliente.","Oferecemos o serviço de make por R$120, sendo necessário confirmar junto ao agendamento.","* Para necessidades diferentes dos pacotes, por favor, entre em contato.","Orçamento válido por 30 dias a partir da data de recebimento.","Orientação de postura e expressão durante a sessão","Tratamento profissional das imagens"]','Presenteie sua mãe com um ensaio fotográfico especial','Um presente que ela vai guardar para sempre. Entre em contato e agende o ensaio de Dia das Mães.','Olá! Gostaria de agendar um ensaio de Dia das Mães (mensagem do site)',1,2);
