INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Pollyanna Gonçalves','63cdb80f-2df3-4e9c-c214-9a8ad4442200',5,NULL,'Um ensaio fotográfico de respeito! Profissional muito competente, me deixou muito a vontade e tornou meu trabalho ainda mais valorizado. Espaço muito lindo, limpo e organizado. Me ajudou até com um difusor pra terminar de secar o meu cabelo.. uma querida!! Super recomendo e desejo muito sucesso ❤️',NULL,1,'corporativo/pollyanna-goncalves',1);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Sheila Lima','ee985c1d-540d-4716-31db-2bb315650e00',5,'Há 8 meses atrás','O lugar é lindo, perfeito para ensaios fotográficos! As fotos ficaram maravilhosas - daquelas que a gente olha e se apaixona.<br> A Lillía é super simpática, envolvente e nos deixa completamente à vontade. Parecia que eu estava com uma amiga de longa data, mesmo sem nunca tê-la visto antes.<br> Foi uma experiência leve, divertida e inesquecível. Recomendo de olhos fechados!','https://maps.app.goo.gl/mCvGFs6XZefjs1SX8',0,'corporativo/05-sheila-lima',2);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Thainá Porto','010e2691-7333-4d8a-0781-ec4208dfe400',5,'Ontem','Minha experiência é SEMPRE maravilhosa!! O estúdio é lindo e muito aconchegante, dá vontade de ficar o dia todinho lá. A lillía é muito simpática, deixa a gente sempre muito a vontade e o trabalho dela é impecável. Recomendo demaaaaisss!!!!','https://maps.app.goo.gl/XYfAgs7nPh3te4RU7',0,'dia-das-maes/thaina-porto',3);
