INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Larissa Costa Mendes','https://lh3.googleusercontent.com/a-/ALV-UjXQdQTB80rZUrvq0boDRBGX82Wa3QgZqmVPI-jtZ6nbKIpD44iq0g=w36-h36-p-rp-mo-br100',5,'4 meses atrás','Fui no estúdio para ensaio corporativo de uma cliente e tanto eu, como ela, amamos o local, os cenários e principalmente o atendimento da Lillia. Ela foi muito atenciosa e acolhedora, nos ajudou, orientou e deixou minha cliente - que chegou bem insegura - super confortável com as fotos.<br>A entrega também foi tudo dentro do prazo e c.otima qualidade.',NULL,0,NULL,15);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Patricia Daniel','https://lh3.googleusercontent.com/a/ACg8ocLw4GEUe7GBvFjP05ZQjFwBO3s50AV57IBDzK0_Q8YTLEG5KA=w36-h36-p-rp-mo-br100',5,'4 meses atrás','Indico de olhos fechados, fiquei muito feliz com o resultado final. Cheguei no Estúdio muito apreensiva, tenho muita vergonha de tirar fotos, mas a Lillia me deixou super a vontade, foi muito paciente e conseguiu que as fotos ficassem maravilhosas. Fico muito grata por toda a atenção e gentileza.',NULL,0,NULL,16);
