INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Magda Tavares','https://lh3.googleusercontent.com/a/ACg8ocIcdOG5dkrJTYy2G0mAU04DWiqLM947bpTCeMLUNsqqYpgoyQ=s72-c-rp-mo-br100',5,'Há 39 semanas','Estúdio maravilhoso, Lilia carinhosa, atenciosa, me deixou muito à vontade. Super recomendo. Nota 1000',NULL,0,NULL,25);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Tatiane Cristina Leal','https://lh3.googleusercontent.com/a/ACg8ocI5YQYDklEK0yVFaF0z-UQPOvB2ArLhD3pGMUsJEsamCjhESA=s72-c-rp-mo-br100',5,'Há 41 semanas','A Lillia foi simplesmente maravilhosa no meu ensaio profissional! Além de extremamente talentosa, ela foi muito simpática e me deixou super à vontade durante toda a sessão, o que foi essencial para um resultado natural e elegante. O estúdio dela é encantador, com ambientes lindos e bem cuidados, perfeitos para composições variadas. As fotos ficaram impecáveis, exatamente o que eu precisava para meu projeto! Recomendo muito o trabalho dela para quem busca qualidade, atenção aos detalhes e um atendimento acolhedor.',NULL,0,NULL,26);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('fabiane oliveira','https://lh3.googleusercontent.com/a-/ALV-UjVT-waQyBKXpwRPrQF8G7JRc6adXBN40kvzvoRfpLhTwfbrUaiXDQ=s72-c-rp-mo-br100',5,'Há 42 semanas','Daria muito mais que 5 estrelas. Que experiência incrível e que profissional. Eu amei meu ensaio, a recepção, o espaço do Studio, que ambiente lindo e acolhedor. Indico, recomendo e farei outros ensaios com certeza.',NULL,0,NULL,27);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Juliana Kozma','b433972a-77c8-4fd9-36d2-5ed969800f00',5,'Há 46 semanas','Maravilhosa! A Lillia é excelente, me senti confortável e linda! É uma dose de autoestima que eu não imaginava que teria em uma sessão de fotos. Os cenários são muito bonitos e as fotos ficaram fantásticas. Simplesmente amei e recomendo muito.',NULL,0,'corporativo/juliana-kozma',28);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Nelma Caroline','24a4d471-034f-42fd-b55a-dd55db869600',5,'Há 47 semanas','Lilllia você é incrível e seu trabalho é impecável! Tirei minhas primeiras fotos profissionais com você e não me arrependo nem um pouco, o carinho, o acolhimento e as conversas deixaram a experiência ainda mais incrível. Obrigada e obrigada! 🥰',NULL,0,'corporativo/nelma-caroline',29);
