INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Bianca Salazar','https://lh3.googleusercontent.com/a/ACg8ocKMqpuGve-NsZ_FH4IkWgIsAvBG1bkDowMSxlLTPNpjrkq-XA=s72-c-rp-mo-br100',5,'Há 49 semanas','O estúdio é lindo e a Lillia é uma excelente profissional! Muito animada, paciente e prestativa. Gostei muito do trabalho e o dia de fotos foi uma delícia! Recomendo demais!',NULL,0,NULL,32);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Evely Lopes Pereira','https://lh3.googleusercontent.com/a/ACg8ocJywtIr07jSVWT9kyMowhNIevBWLfYdNs2MwtV9XVLb-Hfn=s72-c-rp-mo-br100',5,'Há 49 semanas','A Lilia é uma fotógrafa excepcional! Nos deixa super a vontade e orienta para que as fotos fiquem perfeitas! Super recomendo!',NULL,0,NULL,33);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Thamires Marcondes','https://lh3.googleusercontent.com/a-/ALV-UjVizVNyCLRmyzlJpAGzSzI3WpGKZhXllzQJrf9c8naqI7rFrmHRdQ=s72-c-rp-mo-br100',5,'Há 49 semanas','Adoramos o estúdio, muito bem equipado, climatizado, estruturado. Há um espaço grande para desenvolver fotos com tranquilidade. Fomos super bem atendidos pela Lillia desde primeiro contato, agendamento, e no dia. Foi ótima a experiência! E desde então indicamos e quando precisarmos voltaremos!!',NULL,0,NULL,34);
