INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Camila Galdino','https://lh3.googleusercontent.com/a-/ALV-UjVicVJiU4xggSh1I_m8ANexejF94DGiurI6fw_jwtgQAncbUO4g=s72-c-rp-mo-br100',5,'Há 49 semanas','Não tem como ter uma família linda, e não ser registrada pelas mãos de profissional! Ela torna tudo tão leve, ela torna o ensaio o momento mágico, e os resultados são de tirar o fôlego! Eu sempre que puder irei dizer que um sonho realizado foi o ensaio que fizemos com ela. Impecável! Tão breve espero poder registrar mais momentos mágicos com ela! Podem ter certeza não há melhor que ela. Confio de olhos fechados.',NULL,0,NULL,37);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Dani','https://lh3.googleusercontent.com/a-/ALV-UjWOtVJVwMbHUSuhSFYEsCjAPYw4UG0RVaRvg_7Mv2KnFqqGtBkT=s72-c-rp-mo-br100',5,'Há 52 semanas','A Lillia é uma profissional excelente! ! Fiquei muito satisfeita com o trabalho dela. Inicialmente, procurei por algo mais voltado para perfil corporativo, mas ela se destacou não apenas pela qualidade do trabalho, mas também pela simpatia, o que ajudou muito a me sentir confortável, mesmo sendo bem tímida. Sem dúvida, voltarei no futuro para outros tipos de fotos e indicarei seu trabalho. O espaço também é super aconchegante e bem decorado. E Sabemos o quanto bons profissionais são raros nesse mercado, então recomendo fortemente o trabalho da Lillia. Obrigada, Lillia!',NULL,0,NULL,38);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Joelma Lins','https://lh3.googleusercontent.com/a-/ALV-UjUQgZpcgX1RhLsk2wxtwikJSXQbRTcfz7NLGolfT_q4o71POzjiRg=s72-c-rp-mo-ba4-br100',5,'26 de fev. de 2025','Excepcional!!! A Lillia é uma excelente fotógrafa, nos acolhe com um bate-papo, e parece que estamos em casa. O estúdio é lindo, aconchegante, com várias coisinhas pra comer, café de vários tipos e uma estante repleta de livros. Amei!',NULL,0,NULL,39);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Thiago Silva','https://lh3.googleusercontent.com/a-/ALV-UjWVgWI13nWuPHOs5Mt2wn4nYQ1ca3R4H3kB1-ZV26xfTP7AHzUHpg=s72-c-rp-mo-br100',5,'17 de jan. de 2025','Ótimo espaço, estúdio bem equipado e bem localizado',NULL,0,NULL,40);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Mariana Santos','https://lh3.googleusercontent.com/a-/ALV-UjWBWoMygJDnvQWBCQe3NfLgU9lhOgAjfNfFkNecDzFOp9dmklzq=s72-c-rp-mo-br100',5,'1 de jan. de 2025','Eu realizei um sonho em fazer meu ensaio fotográfico e fico muito feliz que escolhi a pessoa certa para esse momento tão importante, a Lillia é uma fotógrafa maravilhosa, ela fez um trabalho impecável em todos os aspectos, a qualidade das fotos é de um nível altíssimo, por isso super recomendo em fazer um ensaio com ela, com certeza não vão se arrepender do trabalho executado, ela é sensacional 👏🏻❤️🥰',NULL,0,NULL,41);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Carla Cah','https://lh3.googleusercontent.com/a-/ALV-UjWOyLmnyMMVCKapd-5Gu9xKMdm5UuhGHeSCEMEnmEc1Ehmg6UM=s72-c-rp-mo-br100',5,'20 de nov. de 2024','Fizemos nosso ensaio de Natal 2024, desde o primeiro contato Lillia foi muito atenciosa, posteriormente conhecemos pessoalmente o estúdio, bem localizado, super equipado e aconchegante. Foi precisa e cirúrgica nas fotos, captando os melhores clicks. Super recomendado. Retornaremos sem dúvidas.',NULL,0,NULL,42);
INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('Alisson Felix','https://lh3.googleusercontent.com/a-/ALV-UjXRyI2UiJks9zOahsaVSowqrDbOiuDmjI1G_rLR8pspusYGGQBuFg=s72-c-rp-mo-br100',5,'25 de set. de 2024','Desde o início, fui acolhido com atenção e carinho, recebendo orientações detalhadas para a realização do meu principal objetivo: o ensaio corporativo. O ambiente, além de aconchegante, permitiu que a cada imagem capturada transmitisse uma emoção natural e espontânea. . Lillia, gratidão por toda atenção, carinho, e experiência que além de única foi marcante. Espero ter outras oportunidades para repetir essa vivência.',NULL,0,NULL,43);
