INSERT OR IGNORE INTO depoimentos (nome,foto_cf_id,rating,data,texto,link,featured,portfolio_link,ordem) VALUES ('karoline siqueira','68e9b783-755e-497c-001b-c2ce5bdb4400',5,'4 de jun. de 2024','Tive o prazer de fazer o meu ensaio corporativo com ela! Foi incrível, ela é excelente em tudo que faz!!!. O espaço oferece um ambiente tranquilo e acolhedor. A beleza do lugar é surreal, muito bem estruturado e pensado para proporcionar comodidade, profissionalismo e fotos memoráveis. Recomendo muitooooooo. Melhor estúdio fotográfico de Mogi.',NULL,0,'corporativo/karoline-siqueira',50);
