-- FAQ Categorias e Perguntas
INSERT OR IGNORE INTO faq_categorias (titulo,slug,ordem) VALUES ('Sobre os Ensaios','ensaios',1);
INSERT OR IGNORE INTO faq_categorias (titulo,slug,ordem) VALUES ('Agendamento e Pagamento','agendamento',2);
INSERT OR IGNORE INTO faq_categorias (titulo,slug,ordem) VALUES ('Sobre as Fotos','fotos',3);
INSERT OR IGNORE INTO faq_categorias (titulo,slug,ordem) VALUES ('Estúdio e Estrutura','estudio',4);

INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='ensaios'),'Quanto tempo dura uma sessão de fotos?','O tempo varia conforme o pacote escolhido. Geralmente, as sessões duram entre 30 minutos (pacotes básicos) e 1 hora e 30 minutos (pacotes premium). O tempo é suficiente para você se sentir à vontade e conseguirmos capturar boas fotos.',1 WHERE (SELECT id FROM faq_categorias WHERE slug='ensaios') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='ensaios') AND pergunta='Quanto tempo dura uma sessão de fotos?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='ensaios'),'Posso levar acompanhante?','Sim! Você pode trazer até 2 acompanhantes para te dar apoio e deixar o ambiente mais confortável. Em alguns pacotes, como ensaio de casal ou família, a participação de outras pessoas já está incluída.',2 WHERE (SELECT id FROM faq_categorias WHERE slug='ensaios') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='ensaios') AND pergunta='Posso levar acompanhante?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='ensaios'),'O que devo vestir para o ensaio?','Recomendo roupas que você se sinta confortável e confiante. Para ensaios corporativos, trajes sociais, social esporte, mas também podemos fazer um alinhamento personalizado. Sempre orientamos sobre as melhores escolhas antes da sessão, ao fechar o pacote, a próxima conversa sempre se trata de cores e detalhes da roupa, baseado no seu guarda-roupa.',3 WHERE (SELECT id FROM faq_categorias WHERE slug='ensaios') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='ensaios') AND pergunta='O que devo vestir para o ensaio?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='ensaios'),'Posso fazer o ensaio fora do estúdio?','Sim! caso queira um ensaio no Parque Centenário ofereço custo zero para ir ao local, caso seja em outro local mais distante da zona central, entre em contato para conversarmos sobre as melhores opções de locais e valores.',4 WHERE (SELECT id FROM faq_categorias WHERE slug='ensaios') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='ensaios') AND pergunta='Posso fazer o ensaio fora do estúdio?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='agendamento'),'Como faço para agendar meu ensaio?','É simples! Entre em contato pelo WhatsApp ou pelo Instagram, escolha o pacote desejado e verificamos a disponibilidade de datas. Solicitamos um sinal de R$150 para confirmar o agendamento.',1 WHERE (SELECT id FROM faq_categorias WHERE slug='agendamento') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='agendamento') AND pergunta='Como faço para agendar meu ensaio?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='agendamento'),'Quais são as formas de pagamento?','Aceitamos PIX, transferência bancária, cartão de crédito (o número de parcelas varia conforme o pacote) e dinheiro.',2 WHERE (SELECT id FROM faq_categorias WHERE slug='agendamento') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='agendamento') AND pergunta='Quais são as formas de pagamento?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='agendamento'),'Posso remarcar minha sessão?','Sim, você pode remarcar com até 48 horas de antecedência sem custos adicionais. Remarcações com menos de 48h podem ter taxa de reagendamento, caso aconteça algo, entre em contato e conversamos sobre a melhor solução.',3 WHERE (SELECT id FROM faq_categorias WHERE slug='agendamento') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='agendamento') AND pergunta='Posso remarcar minha sessão?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='agendamento'),'Qual o prazo para receber as fotos?','O prazo varia conforme o pacote: de 5 a 10 dias úteis. Pacotes premium têm entrega mais rápida. Todas as fotos são entregues via galeria online privada. Temos a opção de redução de prazo, custando R$20 por dia que gostaria de subtrair do prazo.',4 WHERE (SELECT id FROM faq_categorias WHERE slug='agendamento') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='agendamento') AND pergunta='Qual o prazo para receber as fotos?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='fotos'),'Quantas fotos editadas vou receber?','Nossos pacotes incluem todas as fotos editadas, sem limite. O número de fotos varia conforme o pacote contratado, mas garantimos que todas as fotos serão entregues editadas.',1 WHERE (SELECT id FROM faq_categorias WHERE slug='fotos') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='fotos') AND pergunta='Quantas fotos editadas vou receber?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='fotos'),'Posso escolher quais fotos serão editadas?','Sim, enviamos uma pré-seleção das melhores fotos e você pode escolher baseado na quantidade de fotos do pacote contratado. Também oferecemos a opção de escolher as fotos comigo pessoalmente logo após a sessão.',2 WHERE (SELECT id FROM faq_categorias WHERE slug='fotos') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='fotos') AND pergunta='Posso escolher quais fotos serão editadas?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='fotos'),'As fotos têm direitos autorais?','Sim, todas as fotos permanecem com direitos autorais do estúdio. Porém, você tem autorização para uso pessoal ilimitado, inclusive em redes sociais, sempre com os devidos créditos.',3 WHERE (SELECT id FROM faq_categorias WHERE slug='fotos') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='fotos') AND pergunta='As fotos têm direitos autorais?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='fotos'),'Posso comprar fotos adicionais?','Sim! Você pode adquirir fotos extras editadas, impressões, álbuns e outros produtos. Entre em contato para conhecer os valores adicionais.',4 WHERE (SELECT id FROM faq_categorias WHERE slug='fotos') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='fotos') AND pergunta='Posso comprar fotos adicionais?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='estudio'),'Onde fica o estúdio?','O estúdio fica localizado no centro de Mogi das Cruzes/SP em frente ao estacionamento público da prefeitura. Endereço completo é enviado após confirmação do agendamento.',1 WHERE (SELECT id FROM faq_categorias WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='estudio') AND pergunta='Onde fica o estúdio?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='estudio'),'O estúdio tem trocador?','O estúdio conta com um banheiro privativo para você trocar de roupa confortavelmente durante a sessão.',2 WHERE (SELECT id FROM faq_categorias WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='estudio') AND pergunta='O estúdio tem trocador?');
INSERT OR IGNORE INTO faq_perguntas (categoria_id,pergunta,resposta,ordem) SELECT (SELECT id FROM faq_categorias WHERE slug='estudio'),'O estúdio oferece maquiagem?','Maquiagem profissional pode ser adicionada à parte. Consulte as opções disponíveis.',3 WHERE (SELECT id FROM faq_categorias WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM faq_perguntas WHERE categoria_id=(SELECT id FROM faq_categorias WHERE slug='estudio') AND pergunta='O estúdio oferece maquiagem?');

