INSERT OR IGNORE INTO blog_posts (slug,categoria,titulo,descricao,data,imagem_cf_id,ativo,seo_keywords) VALUES ('nosso-cenario-do-dia-das-maes-2025','cenarios-tematicos','Nosso cenário do dia das mães 2025','Cenário especial para o Dia das Mães com arco floral em aramado, sofá redondo e tons pastel delicados. Elegância e carinho para eternizar o amor mais nobre que existe. Porque mãe merece ser retratada como a rainha que é. 👑💖','2025-05-01','58acda17-3c27-42e0-227d-e760faa76d00',1,NULL);
INSERT OR IGNORE INTO blog_posts (slug,categoria,titulo,descricao,data,imagem_cf_id,ativo,seo_keywords) VALUES ('nosso-cenario-do-natal-2024','cenarios-tematicos','Nosso cenário do natal 2024','Preparado com muito carinho para acolher você e sua família neste Natal, cada cantinho foi pensado para trazer aconchego e alegria, longe dos clichês tradicionais.','2024-12-20','d6f77463-35af-4310-e91f-2b2da4a72f00',1,NULL);
INSERT OR IGNORE INTO blog_posts (slug,categoria,titulo,descricao,data,imagem_cf_id,ativo,seo_keywords) VALUES ('nosso-cenario-do-natal-2025','cenarios-tematicos','Nosso cenário do natal 2025','💙 Um cenário cheio de amor, cores suaves e o clima mágico que só o Natal traz. Veja como ficou nosso cenário de Natal 2025 e sinta essa atmosfera especial.','2025-10-14','4cd6c314-924c-4805-aeee-f9c52dc36a00',1,NULL);
INSERT OR IGNORE INTO blog_posts (slug,categoria,titulo,descricao,data,imagem_cf_id,ativo,seo_keywords) VALUES ('quao-importante-e-fazer-um-ensaio-profissional-para-o-linkedin','fotografia-corporativa','Quão importante é fazer um ensaio profissional para o LinkedIn','Descubra por que um ensaio profissional para LinkedIn pode aumentar suas oportunidades em Mogi das Cruzes. Veja como melhorar sua imagem corporativa e transmitir mais confiança.','2026-03-19','7dffc55b-0d58-48c5-b406-a9ce105da100',1,NULL);
INSERT OR IGNORE INTO blog_posts (slug,categoria,titulo,descricao,data,imagem_cf_id,ativo,seo_keywords) VALUES ('vantagens-fotos-corporativas','fotografia-corporativa','As vantagens de investir em fotos corporativas profissionais','Descubra as vantagens do ensaio fotográfico corporativo para profissionais como dentistas, advogados e psicólogos em Mogi das Cruzes.','2025-06-17','9690ece9-9552-4281-01e8-b9bdd0756800',1,NULL);
INSERT OR IGNORE INTO blog_posts (slug,categoria,titulo,descricao,data,imagem_cf_id,ativo,seo_keywords) VALUES ('presente-dia-das-maes-ensaio-fotografico','presentes','Presente de Dia das Mães: Por que um ensaio fotográfico é a melhor escolha em Mogi das Cruzes','Descubra por que um ensaio fotográfico profissional é o presente perfeito para o Dia das Mães em Mogi das Cruzes. Veja como funciona, depoimentos reais e pacotes especiais para surpreender sua mãe.','2026-03-26','4b44edc8-39bf-46ba-9a6e-1257badcd700',1,NULL);

