-- Cenário Páginas e Cenários
INSERT OR IGNORE INTO cenario_paginas (slug,titulo,titulo_pre,ordem) VALUES ('estudio','Cenários','Conheça os',1);
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='estudio'),'Escritório','Nosso escritório no coração de Mogi das Cruzes foi projetado para também ser um cenário, com perfil despojado, seguindo uma palheta de tons claros atende bem todos estilos corporativos, nossa mesa com textura de marmore branco foi desenvolvida exclusivamente para tornar esse ambiente único!','d4e38b52-1ce0-4e1d-03c8-518779aa9800','50e4339d-3ba4-4f6a-4b0d-c8618632fb00','Mulher branca de cabelos enrolados na altura do pescoço sentada na cadeira de escritório branca ela está sorrindo vestida de blusinha roxa','/ensaio-fotografico/corporativo/pollyanna-goncalves','Pollyanna Gonçalves','paisagem',1 WHERE (SELECT id FROM cenario_paginas WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='estudio') AND titulo='Escritório');
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='estudio'),'Cenário Intimista','Desde o início de sua jornada como fotógrafa em 2018, Lillia Tavares trabalha com fotos sensual intimistas, sendo elas grande inspiração para um olhar delicado e de bom gosto, para que os modelos tenham a melhor visão de sua real beleza. Fizemos esse cantinho pensando na estética boho, esse é o único cenário nesse estilo em Mogi das Cruzes.','5aaf4778-101f-4296-bd37-a5e870ea3400',NULL,NULL,NULL,NULL,NULL,2 WHERE (SELECT id FROM cenario_paginas WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='estudio') AND titulo='Cenário Intimista');
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='estudio'),'Fundos infinitos','Atualmemente oferecemos 4 opções de cores de fundos fotográficos dois claros (bege e branco) e dois escuros (grafite e azul marinho), além da iluminação profissional e de alguns acessórios, como banquetas, uma poltrona, e caixas brancas.','b6dc36df-86b3-4485-52de-8b91ba144f00','9cfdca56-4b5a-4d12-ae0d-2cfc92489f00','Mulher de cabelos enrolados e blazer azul, esla está de pé com uma perna apoiada em um box branco de madeira 30cm x 30cm','/ensaio-fotografico/corporativo/vanessa-lima','Vanessa Lima','retrato',3 WHERE (SELECT id FROM cenario_paginas WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='estudio') AND titulo='Fundos infinitos');
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='estudio'),'Cantinho do espelho','O canto preferido da fotógrafa Lillia Tavares para suas selfies, a combinação da parede de madeira freijó com o laranja e o verde das plantas trazem uma estética bem agradável para sua fotos.','e8d30eab-936f-45fd-b450-a21295e9a200','60ddc9c8-058d-441e-1608-ca6109de1200','Mulher sorrindo de roupa branca, sentada no chão, uma parte da parede é de madeira freijó, outra, é laranja, há um vaso de plantas grande, e um espelho grande','/ensaio-fotografico/corporativo/andresa-maia','Andresa Maia','paisagem',4 WHERE (SELECT id FROM cenario_paginas WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='estudio') AND titulo='Cantinho do espelho');
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='estudio'),'Sofá da recepção','A arquiteta <a href="https://www.instagram.com/studiocnmais" target="_blank">Camila Nogueira</a> estava inspirada ao pensar todos as funções do estúdio como um cenário, sim, nosso cantinho da recepção também tem essa função ❤️, os quadros remetem a referências estéticas da fotógrafa.','de0a3700-d07a-46fd-1f69-8cc47ebca000','ba0f1af3-4673-47e4-ab41-28bf987e9800','Um canto com um sofá e vários quadros na parede verde musgo, Mulher branca de cabelos enrolados na altura do pescoço sentada no sofá ela está sorrindo vestida de blusinha roxa e calça bege, seu braço esquerdo está apoiado nos braços do sofá, o direito segurando uma xícara de café','/ensaio-fotografico/corporativo/pollyanna-goncalves','Pollyanna Gonçalves','paisagem',5 WHERE (SELECT id FROM cenario_paginas WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='estudio') AND titulo='Sofá da recepção');
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='estudio'),'Sofá','Junto com o cenário intimista, esse é o cenário que mais se beneficia da luz natural e isso traz um grande benefício para a estética de suas fotos, aproveite o período da tarde para tornar suas fotos ainda melhores','8e112adf-8f3a-4ca8-0d95-ea0176b80600','0a37ed18-db3d-49b2-ac20-68f472793f00',NULL,'/ensaio-fotografico/corporativo/andresa-maia','Andresa Maia','paisagem',6 WHERE (SELECT id FROM cenario_paginas WHERE slug='estudio') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='estudio') AND titulo='Sofá');
INSERT OR IGNORE INTO cenario_paginas (slug,titulo,titulo_pre,ordem) VALUES ('dia-das-maes-2025','dia das mães 2025','Conheça nosso cenário do',1);
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025'),'O Cenário','Para uma visão geral do cenário que preparamos para o <b>Dia das Mães 2025</b> fizemos um cantinho cheio de sofisticação com cores puxadas para o dourado e off-white.','58acda17-3c27-42e0-227d-e760faa76d00','b25c4856-522b-4367-2aac-6f1c36111100','No fundo cenário do dia das mães: Sentadas no sofá da esquerda pra direita: Uma mulher (a mãe) com vestido longo azul, uma mulher mais velha com paletó branco, calça branca e camisa azul (a avó), e uma mulher mais nova com uma blusinha branca e uma camisa listrada azul por cima, e calça azul, as três mulheres são negras de cabelos crespos','/ensaio-fotografico/dia-das-maes-2025/lillia-tavares','Dia das Mães - Lillia Tavares',NULL,1 WHERE (SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025') AND titulo='O Cenário');
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025'),'Decoração','Um zoom nos detalhes da decoração que escolhemos para o cenário do Dia das Mães.','49636a87-a093-4577-4b61-4b1bed232500',NULL,NULL,NULL,NULL,NULL,2 WHERE (SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025') AND titulo='Decoração');
INSERT OR IGNORE INTO cenarios (pagina_id,titulo,descricao,imagem_bg_cf_id,imagem_exemplo_cf_id,imagem_exemplo_alt,imagem_exemplo_link,imagem_exemplo_titulo,imagem_exemplo_orientacao,ordem) SELECT (SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025'),'Floral','No <b>Dia das Mães</b> não podem faltar as flores, e demos nosso melhor para que as cores do arranjo converse perfeitamente com todos os elementos do cenário, esperamos que você tenha gostado.','6ea326b0-e9e1-4b05-29c1-46146f52a400','1754195e-e114-473f-941f-bfd589ab7a00','No fundo cenário do dia das mães: Uma mulher em pé com calça bege, e uma blusinha de manga longa branca, sentada de mãos dadas está uma mulher mais nova com uma blusinha branca e uma camisa listrada azul por cima, e calça azul, as duas mulheres são negras de cabelos crespos','/ensaio-fotografico/dia-das-maes-2025/lillia-tavares','Dia das Mães - Lillia Tavares','retrato',3 WHERE (SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cenarios WHERE pagina_id=(SELECT id FROM cenario_paginas WHERE slug='dia-das-maes-2025') AND titulo='Floral');
